import {rows} from "@/lib/clearpath"; import {Badge,PageHead} from "@/components/Portal"; import {UnavailableButton} from "../PageControls";
export default function Vendors(){const d=rows("SELECT * FROM cp_vendors");return <div className="page"><PageHead eyebrow="RESEARCH NETWORK" title="Vendor Directory" subtitle="Approved screening and court research partners." actions={<UnavailableButton className="btn primary" reason="Vendor creation is disabled in this demo">+ Add Vendor</UnavailableButton>}/><div className="vendor-grid">{d.map(r=><section className="card vendor" key={String(r.id)}><div><span>{String(r.name).split(" ").map(x=>x[0]).join("").slice(0,2)}</span><Badge tone="green">{r.status}</Badge></div><h2>{r.name}</h2><p>{r.coverage}</p><dl><dt>Jurisdictions</dt><dd>{r.jurisdictions}</dd><dt>Average turnaround</dt><dd>{r.turnaround}</dd><dt>Standard cost</dt><dd>${r.cost}</dd><dt>Quality score</dt><dd><b>{r.quality}%</b></dd><dt>Contact</dt><dd><a href={`mailto:${r.contact}`}>{r.contact}</a></dd></dl>{r.preferred===1&&<Badge tone="blue">★ Preferred Vendor</Badge>}<a className="btn outline wide" href={`mailto:${r.contact}?subject=ClearPath vendor inquiry`}>Contact Vendor</a></section>)}</div></div>}
